INSERT INTO def VALUES(88,'is_alpha','fn',NULL,'is_alpha c = (c >= 65 && c <= 90) || (c >= 97 && c <= 122) || c == 95',X'c500000000000000000000000000000000000000000000000000000000000001',25,1,'2026-02-21 11:19:47','2026-02-21 11:19:47',1);
INSERT INTO def VALUES(89,'is_digit','fn',NULL,'is_digit c = c >= 48 && c <= 57',X'c500000000000000000000000000000000000000000000000000000000000002',10,1,'2026-02-21 11:19:47','2026-02-21 11:19:47',1);
INSERT INTO def VALUES(90,'is_alnum','fn',NULL,'is_alnum c = is_alpha(c) || is_digit(c)',X'c500000000000000000000000000000000000000000000000000000000000003',8,1,'2026-02-21 11:19:47','2026-02-21 11:19:47',1);
